SELECT operation_time, AVG(cull_cost) AS average_cull_cost
FROM culling_operations
GROUP BY operation_time;

SELECT climate_zone, SUM(total_trees) AS total_trees_in_zone
FROM forest_sites
GROUP BY climate_zone;

SELECT DISTINCT operation_id
FROM culling_operations
ORDER BY operation_id;

SELECT operation_id, operation_time, actual_trees, cull_cost
FROM culling_operations
WHERE operation_time > 2022;

SELECT site_name, total_trees
FROM forest_sites
ORDER BY total_trees DESC;

SELECT AVG(area) AS average_area
FROM forest_sites
WHERE climate_zone = 'Tropical';

SELECT AVG(fs.total_trees) AS avg_total_trees
FROM forest_sites fs
JOIN culling_operations co ON fs.site_id = co.site_id;

SELECT site_name, area
FROM forest_sites
ORDER BY area DESC;
